"use client";

import * as React from "react";
import { Suspense } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { CheckCircle2, ArrowRight, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { confirmBillingTransaction, fetchBillingAccount, type BillingAccountPayload } from "@/lib/billing-client";

export default function BillingSuccessPage() {
    return (
        <Suspense fallback={null}>
            <BillingSuccessPageContent />
        </Suspense>
    );
}

function BillingSuccessPageContent() {
    const searchParams = useSearchParams();
    const [status, setStatus] = React.useState<"checking" | "trial" | "active" | "pending" | "auth" | "error">("checking");
    const [billingAccount, setBillingAccount] = React.useState<BillingAccountPayload | null>(null);

    React.useEffect(() => {
        let cancelled = false;
        const reference = searchParams.get("reference")?.trim() || "";

        function applyAccount(account: BillingAccountPayload): boolean {
            if (account.account.lastError) {
                if (!cancelled) {
                    setBillingAccount(account);
                    setStatus("error");
                }
                return true;
            }

            if (account.entitlements.status === "trialing" && account.entitlements.planId !== "free") {
                if (!cancelled) {
                    setBillingAccount(account);
                    setStatus("trial");
                }
                return true;
            }

            if (account.entitlements.isActive && account.entitlements.planId !== "free") {
                if (!cancelled) {
                    setBillingAccount(account);
                    setStatus("active");
                }
                return true;
            }

            return false;
        }

        async function confirmBilling() {
            for (let attempt = 0; attempt < 8; attempt += 1) {
                if (reference) {
                    try {
                        const confirmed = await confirmBillingTransaction(reference);
                        if (applyAccount(confirmed)) {
                            return;
                        }
                    } catch {
                        // Keep polling briefly while the webhook or verification catches up.
                    }
                }

                try {
                    const account = await fetchBillingAccount();
                    if (!account) continue;
                    if (applyAccount(account)) {
                        return;
                    }
                } catch {
                    // Keep polling briefly while the webhook catches up.
                }

                await new Promise((resolve) => setTimeout(resolve, 1500));
            }

            if (!cancelled) setStatus("pending");
        }

        void confirmBilling();
        return () => {
            cancelled = true;
        };
    }, [searchParams]);

    const trialEnds = billingAccount?.account.trialEndsAt
        ? new Date(billingAccount.account.trialEndsAt).toLocaleDateString("en-ZA")
        : null;
    const nextCharge = billingAccount?.account.nextChargeAt
        ? new Date(billingAccount.account.nextChargeAt).toLocaleDateString("en-ZA")
        : null;
    const reference = searchParams.get("reference")?.trim() || "";
    const successPath = reference
        ? `/billing/success?reference=${encodeURIComponent(reference)}&claim=1`
        : "/billing/success?claim=1";

    const title = status === "trial"
        ? "Thank you, your trial is active"
        : status === "active"
            ? "Thank you, payment confirmed"
            : status === "error"
                ? "Payment received, but setup needs attention"
        : status === "auth"
            ? "Thank you for your order"
            : status === "pending"
                ? "Finishing your activation"
                : "Confirming payment";

    const message = status === "trial"
        ? `Your 14-day trial is active${trialEnds ? ` until ${trialEnds}` : ""}. ${nextCharge ? `Your first real charge is scheduled for ${nextCharge} unless you cancel first.` : "We are still saving your next charge date."}`
        : status === "active"
            ? `Your paid features are active${nextCharge ? ` and the next renewal is scheduled for ${nextCharge}` : ""}. Encrypted sync will be available soon.`
        : status === "error"
            ? billingAccount?.account.lastError || "Your card setup completed, but the billing details still need a final check."
            : status === "pending"
                ? "LekkerLedger is still finishing the payment confirmation. This usually takes a few seconds."
                : "LekkerLedger is checking Paystack and your billing status now. This usually takes a few seconds.";

    return (
        <div className="min-h-[80vh] flex flex-col items-center justify-center p-4 text-center">
            <div className="relative mb-6">
                <div className="absolute inset-0 animate-ping rounded-full" style={{ backgroundColor: "var(--success-soft)" }} />
                <div className="relative rounded-full p-4 text-white shadow-xl" style={{ backgroundColor: "var(--success)" }}>
                    {status === "checking" ? <Loader2 className="h-12 w-12 animate-spin" /> : <CheckCircle2 className="h-12 w-12" />}
                </div>
            </div>

            <h1 className="text-3xl font-black mb-3">{title}</h1>
            <p className="text-[var(--text-muted)] max-w-md mb-8 leading-relaxed">
                {message}
            </p>

            <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md">
                <Link href="/dashboard" className="w-full">
                    <Button className="w-full h-12 gap-2 bg-[var(--primary)] text-white font-bold rounded-2xl">
                        Open Dashboard <ArrowRight className="h-4 w-4" />
                    </Button>
                </Link>
                <Link href="/upgrade" className="w-full">
                    <Button variant="outline" className="w-full h-12 font-bold rounded-2xl">
                        Manage Billing
                    </Button>
                </Link>
            </div>
        </div>
    );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import {
    ArrowRight, AlertTriangle,
    FileText, FolderOpen,
    BookOpen, ChevronRight, Banknote,
    ShieldCheck, UserPlus, Settings,
} from "lucide-react";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { PageHeader } from "@/components/ui/page-header";
import { CardSkeleton, StatSkeleton } from "@/components/ui/loading-skeleton";
import { SyncStatusBadge } from "@/components/ui/sync-status-badge";
import { getEmployees, getSettings, getCurrentPayPeriod, getDocuments, getLatestPayslip, subscribeToDataChanges, getPayPeriods } from "@/lib/storage";
import { filterRecordsForArchiveWindow, isUploadedDocument } from "@/lib/archive";
import { computeDashboardAlerts, type DashboardAlert as DashboardAlertData } from "@/lib/alerts";
import { getUserPlan } from "@/lib/entitlements";
import { Employee, PayPeriod, EmployerSettings, DocumentMeta, PayslipInput } from "@/lib/schema";
import { calculatePayslip } from "@/lib/calculator";
import { InlinePlanCheckoutButton } from "@/components/billing/inline-paid-plan-checkout";


interface EmployeeSummary {
    employee: Employee;
    latestPayslip: PayslipInput | null;
    netPay: number | null;
}

function DashboardContent() {
    const [loading, setLoading] = React.useState(true);
    const [employees, setEmployees] = React.useState<Employee[]>([]);
    const [settings, setSettings] = React.useState<EmployerSettings | null>(null);
    const [currentPeriod, setCurrentPeriod] = React.useState<PayPeriod | null>(null);
    const [recentDocs, setRecentDocs] = React.useState<DocumentMeta[]>([]);
    const [summaries, setSummaries] = React.useState<EmployeeSummary[]>([]);
    const [allPeriods, setAllPeriods] = React.useState<PayPeriod[]>([]);
    const searchParams = useSearchParams();
    const paidLoginRequested = searchParams.get("paidLogin") === "1";
    const paidLoginNext = searchParams.get("next");
    const skipPaidChecks = !!paidLoginNext && paidLoginNext.startsWith("/upgrade");
    const activationSuccess = searchParams.get("activation") === "paid-login-success";
    const activationSync = searchParams.get("sync");

    React.useEffect(() => {
        if (paidLoginRequested) return;

        let active = true;
        async function load() {
            if (active) {
                setLoading(true);
            }
            const [emps, s, period, docs, allP] = await Promise.all([
                getEmployees(),
                getSettings(),
                getCurrentPayPeriod(),
                getDocuments(),
                getPayPeriods(),
            ]);

            // Build employee summaries for alert engine
            const results: EmployeeSummary[] = [];
            for (const emp of emps) {
                const latest = await getLatestPayslip(emp.id);
                let netPay: number | null = null;
                if (latest) netPay = calculatePayslip(latest).netPay;
                results.push({ employee: emp, latestPayslip: latest, netPay });
            }

            if (!active) return;
            const plan = getUserPlan(s);
            const visibleRecentDocs = filterRecordsForArchiveWindow(docs, plan, (doc) => doc.createdAt, {
                alwaysVisible: isUploadedDocument,
            }).visible;
            setEmployees(emps);
            setSettings(s);
            setCurrentPeriod(period);
            setAllPeriods(allP);
            setRecentDocs(visibleRecentDocs.slice(0, 5));
            setSummaries(results);
            setLoading(false);
        }
        load();

        const unsubscribe = subscribeToDataChanges(load);
        return () => {
            active = false;
            unsubscribe();
        };
    }, [paidLoginRequested]);

    if (paidLoginRequested) {
        return (
            <>
                <PageHeader title="Dashboard" subtitle="Completing your setup." />
                <p className="text-sm text-[var(--text-muted)]">Completing your setup...</p>
            </>
        );
    }

    if (loading) {
        return (
            <div className="space-y-6">
                <PageHeader title="Dashboard" subtitle="Loading your household overview..." />
                <div className="grid gap-6 lg:grid-cols-12">
                    <div className="lg:col-span-8 space-y-6">
                        <CardSkeleton />
                        <CardSkeleton />
                    </div>
                    <div className="lg:col-span-4 space-y-6">
                        <StatSkeleton />
                        <CardSkeleton />
                    </div>
                </div>
            </div>
        );
    }

    const employeeCount = employees.length;
    const completedEntries = currentPeriod?.entries.filter(e => e.status === "complete").length ?? 0;
    const totalEntries = currentPeriod?.entries.length ?? 0;
    const progressPercent = totalEntries > 0 ? (completedEntries / totalEntries) * 100 : 0;
    const currentMonth = format(new Date(), "MMMM yyyy");

    // Alert engine
    const now = new Date();
    const alerts = computeDashboardAlerts({ employees, summaries, settings, now });

    const isSetupIncomplete = employeeCount === 0;
    const isPayrollStarted = !!currentPeriod;
    const isPayrollReady = completedEntries === totalEntries && totalEntries > 0 && currentPeriod?.status !== "review";
    const isPayrollInReview = currentPeriod?.status === "review";

    return (
        <div className="pb-8 space-y-6">
            <PageHeader
                title="Dashboard"
                subtitle={isSetupIncomplete ? "Let's get your household payroll set up." : "Manage your monthly payroll and records."}
            />

            {activationSuccess && <ActivationAlert syncState={activationSync} settings={settings} />}

            <div className="grid gap-6 lg:grid-cols-12 items-start">
                {/* Left Column: Primary Focus */}
                <div className="lg:col-span-8 space-y-6">
                    {/* 1. Primary Task Hero */}
                    <PrimaryTaskHero
                        currentPeriod={currentPeriod}
                        isSetupIncomplete={isSetupIncomplete}
                        isPayrollReady={isPayrollReady}
                        isPayrollInReview={isPayrollInReview}
                        progressPercent={progressPercent}
                        completedEntries={completedEntries}
                        totalEntries={totalEntries}
                        currentMonth={currentMonth}
                        allPeriods={allPeriods}
                    />

                    {/* 3. Next-Steps Checklist (Only if setup is incomplete or no payroll) */}
                    {(isSetupIncomplete || !isPayrollStarted) && (
                        <OnboardingChecklist
                            employeeCount={employeeCount}
                            isPayrollStarted={isPayrollStarted}
                            settings={settings}
                        />
                    )}

                    {/* 2. Compact Household Snapshot (Mobile only, stacks below hero) */}
                    <div className="lg:hidden">
                        <HouseholdSnapshot
                            employeeCount={employeeCount}
                            documentCount={recentDocs.length}
                            settings={settings}
                        />
                    </div>

                    {/* Quick Access ΓÇö mobile only (appears early, before alerts) */}
                    <div className="lg:hidden">
                        <QuickActions />
                    </div>

                    {/* Alert banners */}
                    <div className="space-y-3">
                        {alerts.map(alert => (
                            <DashboardAlert key={alert.id} alert={alert} />
                        ))}
                    </div>

                    {/* 5. Recent Records Area */}
                    <RecentRecordsArea recentDocs={recentDocs} hasEmployees={employeeCount > 0} />
                </div>

                {/* Right Column: Supporting Info (desktop only) */}
                <div className="lg:col-span-4 space-y-6">
                    {/* 2. Compact Household Snapshot (Desktop) */}
                    <div className="hidden lg:block">
                        <HouseholdSnapshot
                            employeeCount={employeeCount}
                            documentCount={recentDocs.length}
                            settings={settings}
                        />
                    </div>

                    {/* 4. Quick Access Block (desktop only ΓÇö mobile version is above) */}
                    <div className="hidden lg:block">
                        <QuickActions />
                    </div>

                    {/* Upgrade nudge for free users */}
                    {getUserPlan(settings).id === "free" && (
                        <div className="rounded-xl border border-[var(--border)] bg-[var(--surface-1)] p-3 sm:p-4 space-y-2">
                            <p className="text-xs font-semibold text-[var(--text)]">Standard adds 2 more workers, encrypted sync, and leave tracking ΓÇö R29/month.</p>
                            <InlinePlanCheckoutButton
                                planId="standard"
                                billingCycle="monthly"
                                variant="link"
                                className="h-auto min-h-0 px-0 py-0 text-xs font-bold"
                            >
                                <>
                                    R1 for 14 days <ArrowRight className="h-3 w-3" />
                                </>
                            </InlinePlanCheckoutButton>
                        </div>
                    )}

                    {/* 6. Advanced/Annual (Quiet) */}
                    <div className="pt-2">
                        <ComplianceCard />
                    </div>

                    {/* Help & Support */}
                    <div className="pt-4 border-t border-[var(--border)]">
                        <Link href="/help/admin" className="group flex items-center gap-3 text-sm font-semibold text-[var(--text-muted)] hover:text-[var(--primary)] transition-colors">
                            <div className="p-1.5 rounded-lg bg-[var(--surface-2)] group-hover:bg-[var(--primary)]/10 transition-colors">
                                <BookOpen className="h-4 w-4" />
                            </div>
                            Help &amp; Support
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
}

function ActivationAlert({ syncState, settings }: { syncState: string | null; settings: EmployerSettings | null }) {
    const backupLabel = "not yet";

    return (
        <Card className="overflow-hidden border-2 border-[var(--primary)] bg-[var(--surface-raised)] shadow-lg">
            <CardContent className="space-y-3 p-6">
                <div className="flex items-center gap-3 text-[var(--primary)]">
                    <div className="rounded-full bg-[var(--primary)]/10 p-2">
                        <ShieldCheck className="h-5 w-5" />
                    </div>
                    <h3 className="text-lg font-black italic tracking-tight">Paid login activated</h3>
                </div>
                <p className="text-sm font-medium leading-relaxed text-[var(--text-muted)]">
                    {syncState === "none"
                        ? "Paid login is complete. No data snapshot was required yet on this device."
                        : `Last backup: ${backupLabel}.`}
                </p>
            </CardContent>
        </Card>
    );
}

function PrimaryTaskHero({
    currentPeriod,
    isSetupIncomplete,
    isPayrollReady,
    isPayrollInReview,
    progressPercent,
    completedEntries,
    totalEntries,
    currentMonth,
    allPeriods,
}: {
    currentPeriod: PayPeriod | null;
    isSetupIncomplete: boolean;
    isPayrollReady: boolean;
    isPayrollInReview: boolean;
    progressPercent: number;
    completedEntries: number;
    totalEntries: number;
    currentMonth: string;
    allPeriods: PayPeriod[];
}) {
    const latestPeriod = allPeriods[0];
    const isLatestLocked = latestPeriod?.status === "locked";
    const isLatestCurrentMonth = latestPeriod?.name === currentMonth;

    const title = currentPeriod
        ? isPayrollInReview
            ? `${currentPeriod.name} ΓÇö Review in progress`
            : isPayrollReady
                ? `${currentPeriod.name} is ready`
                : `${currentPeriod.name} in progress`
        : isLatestLocked && isLatestCurrentMonth
            ? `${currentMonth} finalised`
            : isSetupIncomplete
                ? "Welcome to LekkerLedger"
                : `Set up ${currentMonth}`;

    const subtitle = currentPeriod
        ? isPayrollInReview
            ? "This pay run is in the review stage. Open it to finalise and generate payslips."
            : isPayrollReady
                ? "All employee entries are complete. You can now finalise this month and generate payslips."
                : `You have completed ${completedEntries} of ${totalEntries} entries. Finish the rest to finalise payroll.`
        : isLatestLocked && isLatestCurrentMonth
            ? `Payroll for ${currentMonth} is complete and locked. You can view all generated records in the Documents Hub.`
            : isSetupIncomplete
                ? "Welcome to LekkerLedger. Let's get your household payroll set upΓÇöstarting with your employer details and first employee."
                : `Start the ${currentMonth} pay period to track hours and generate payslips for your household.`;

    const primaryActionHref = currentPeriod
        ? `/payroll/${currentPeriod.id}`
        : isLatestLocked && isLatestCurrentMonth
            ? "/documents"
            : isSetupIncomplete
                ? "/settings"
                : "/payroll/new";

    const primaryActionLabel = currentPeriod
        ? isPayrollInReview ? "Review & Finalise" : isPayrollReady ? "Review & Finalise" : "Continue Payroll"
        : isLatestLocked && isLatestCurrentMonth
            ? "View Documents"
            : isSetupIncomplete ? "Start Setup" : `Start ${currentMonth}`;

    return (
        <Card className="relative overflow-hidden border-none shadow-premium bg-[var(--surface-raised)] group">
            {/* Subtle background pattern/gradient */}
            <div className="absolute inset-0 bg-gradient-to-br from-[var(--primary)]/5 via-transparent to-transparent opacity-50" />

            <CardContent className="relative space-y-4 p-4 sm:p-6 md:p-8">
                <div className="space-y-2">
                    <p className="type-overline text-[var(--primary)] flex items-center gap-2">
                        <span className="h-1.5 w-1.5 rounded-full bg-[var(--primary)] animate-pulse" />
                        {currentPeriod ? "Current Pay Period" : "Getting Started"}
                    </p>
                    <div className="max-w-2xl">
                        <h2 className="text-xl sm:text-2xl md:text-3xl font-black tracking-tight text-[var(--text)] mb-1.5 leading-tight">
                            {title}
                        </h2>
                        <p className="text-sm sm:text-base text-[var(--text-muted)] leading-relaxed font-medium">
                            {subtitle}
                        </p>
                    </div>
                </div>

                {currentPeriod && (
                    <div className="max-w-md space-y-2">
                        <div className="flex items-center justify-between text-xs font-bold text-[var(--text-muted)] uppercase tracking-wider">
                            <span>Progress</span>
                            <span>{Math.round(progressPercent)}%</span>
                        </div>
                        <div className="h-2.5 overflow-hidden rounded-full bg-[var(--surface-2)] shadow-inner">
                            <div
                                className="h-full rounded-full bg-[var(--primary)] transition-all duration-700 ease-out"
                                style={{ width: `${progressPercent}%` }}
                            />
                        </div>
                    </div>
                )}

                <div className="flex flex-col sm:flex-row flex-wrap gap-3 pt-1">
                    <Link href={primaryActionHref} className="sm:w-auto">
                        <Button className="w-full sm:w-auto h-11 px-5 gap-2 rounded-xl bg-[var(--primary)] font-bold text-white hover:bg-[var(--primary-hover)] shadow-lg shadow-[var(--primary)]/20 transition-all active:scale-[0.98]">
                            {primaryActionLabel}
                            <ArrowRight className="h-4 w-4 shrink-0" />
                        </Button>
                    </Link>
                    {!isSetupIncomplete && (
                        <Link href="/employees" className="sm:w-auto">
                            <Button variant="outline" className="w-full sm:w-auto h-11 px-5 gap-2 rounded-xl border-[var(--border)] font-bold text-[var(--text)] hover:bg-[var(--surface-2)] transition-colors">
                                View Employees
                            </Button>
                        </Link>
                    )}
                </div>
            </CardContent>
        </Card>
    );
}

function OnboardingChecklist({ employeeCount, isPayrollStarted, settings }: { employeeCount: number; isPayrollStarted: boolean; settings: EmployerSettings | null }) {
    const employerDetailsCompleted = !!settings?.employerName;
    
    const steps = [
        {
            label: "Add employer details",
            description: "Your name, address, and contact info for payslips.",
            completed: employerDetailsCompleted,
            href: "/settings?tab=general"
        },
        {
            label: "Add your first employee",
            description: "Full name and basic contact details.",
            completed: employeeCount > 0,
            href: "/employees/new"
        },
        {
            label: "Set hourly rates & schedule",
            description: "Required for accurate payslip calculations.",
            completed: employeeCount > 0, // Simplified check
            href: "/employees"
        },
        {
            label: "Start your first pay period",
            description: "Record actual hours worked this month.",
            completed: isPayrollStarted,
            href: "/payroll/new"
        }
    ];

    return (
        <Card className="glass-panel border-none">
            <CardContent className="p-4 sm:p-6 space-y-3">
                <div className="flex items-center justify-between">
                    <h3 className="text-base sm:text-lg font-black text-[var(--text)]">Next Steps</h3>
                    <p className="text-xs font-black uppercase tracking-widest text-[var(--text-muted)]">Setup Progress</p>
                </div>
                <div className="space-y-3">
                    {steps.map((step, i) => (
                        <Link key={i} href={step.completed ? "#" : step.href}>
                            <div className={`group flex items-center gap-4 p-4 rounded-xl border transition-all ${step.completed ? "bg-[var(--surface-2)]/30 border-transparent opacity-60" : "bg-[var(--surface-1)] border-[var(--border)] hover:border-[var(--primary)]/30 hover:shadow-md cursor-pointer"}`}>
                                <div className={`flex h-6 w-6 shrink-0 items-center justify-center rounded-full border-2 transition-colors ${step.completed ? "bg-[var(--success)] border-[var(--success)] text-white" : "border-[var(--border)] group-hover:border-[var(--primary)]"}`}>
                                    {step.completed ? <ShieldCheck className="h-4 w-4" /> : <span className="text-xs font-bold">{i + 1}</span>}
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-[var(--text)]">{step.label}</p>
                                    <p className="text-xs text-[var(--text-muted)] font-medium">{step.description}</p>
                                </div>
                                {!step.completed && <ChevronRight className="h-4 w-4 ml-auto text-[var(--text-muted)] group-hover:text-[var(--primary)] transition-colors" />}
                            </div>
                        </Link>
                    ))}
                </div>
            </CardContent>
        </Card>
    );
}

function HouseholdSnapshot({ employeeCount, documentCount, settings }: { employeeCount: number; documentCount: number; settings: EmployerSettings | null }) {
    return (
        <Card className="glass-panel border-none shadow-sm outline outline-1 outline-[var(--border)]">
            <CardContent className="p-4 sm:p-6 space-y-4">
                <div>
                    <p className="text-xs font-black uppercase tracking-[0.2em] text-[var(--text-muted)] mb-0.5">Snapshot</p>
                    <h3 className="text-base sm:text-lg font-black text-[var(--text)]">Household Metrics</h3>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-wider">Active Employees</p>
                        <p className="text-2xl font-black text-[var(--text)]">{employeeCount}</p>
                    </div>
                    <div className="space-y-1">
                        <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-wider">Documents</p>
                        <p className="text-2xl font-black text-[var(--text)]">{documentCount}</p>
                    </div>
                </div>

                <div className="pt-4 border-t border-[var(--border)]">
                    <div className="flex items-center justify-between gap-3 text-xs">
                        <span className="font-bold text-[var(--text-muted)]">Storage & Sync</span>
                        <SyncStatusBadge state={"disconnected"} />
                    </div>
                </div>
            </CardContent>
        </Card>
    );
}

function QuickActions() {
    const actions = [
        { label: "Add Employee", icon: UserPlus, href: "/employees/new", primary: true },
        { label: "Monthly Payroll", icon: Banknote, href: "/payroll" },
        { label: "Documents Hub", icon: FolderOpen, href: "/documents" },
        { label: "Account Settings", icon: Settings, href: "/settings" }
    ];

    return (
        <div className="space-y-4">
            <h3 className="type-overline text-[var(--text-muted)] px-1">Quick Access</h3>
            <div className="grid gap-2">
                {actions.map((action, i) => (
                    <Link key={i} href={action.href}>
                        <Button
                            variant="ghost"
                            className="w-full h-12 justify-start gap-4 px-4 rounded-xl font-bold bg-[var(--surface-1)] border border-[var(--border)] hover:bg-[var(--surface-2)] hover:border-[var(--primary)]/20 transition-all group"
                        >
                            <div className="p-1.5 rounded-lg bg-[var(--surface-2)] group-hover:bg-[var(--primary)]/10 transition-colors">
                                <action.icon className="h-4 w-4 text-[var(--text-muted)] group-hover:text-[var(--primary)]" />
                            </div>
                            <span className="text-[13px] text-[var(--text)]">{action.label}</span>
                        </Button>
                    </Link>
                ))}
            </div>
        </div>
    );
}

function RecentRecordsArea({ recentDocs, hasEmployees }: { recentDocs: DocumentMeta[]; hasEmployees: boolean }) {
    if (!hasEmployees) return null;

    return (
        <Card className="glass-panel border-none">
            <CardContent className="p-4 sm:p-6 space-y-4">
                <div className="flex items-center justify-between">
                    <div>
                        <p className="text-xs font-black uppercase tracking-[0.2em] text-[var(--text-muted)] mb-0.5">Recent Activity</p>
                        <h3 className="text-base sm:text-lg font-black text-[var(--text)]">Recent Records</h3>
                    </div>
                    {recentDocs.length > 0 && (
                        <Link href="/documents">
                            <Button variant="ghost" size="sm" className="text-xs font-bold text-[var(--primary)] hover:bg-[var(--primary)]/5 h-8 rounded-lg">
                                View all
                            </Button>
                        </Link>
                    )}
                </div>

                {recentDocs.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-10 text-center space-y-3 bg-[var(--surface-2)]/30 rounded-2xl border border-dashed border-[var(--border)]">
                        <div className="h-10 w-10 rounded-full bg-[var(--surface-2)] flex items-center justify-center">
                            <FileText className="h-5 w-5 text-[var(--text-muted)]" />
                        </div>
                        <div className="space-y-1">
                            <p className="text-sm font-bold text-[var(--text)]">No records yet</p>
                            <p className="text-xs text-[var(--text-muted)] max-w-[200px] font-medium leading-relaxed">
                                Complete a pay period to generate payslips and UI records.
                            </p>
                        </div>
                    </div>
                ) : (
                    <div className="divide-y divide-[var(--border)]">
                        {recentDocs.slice(0, 3).map(doc => (
                            <Link key={doc.id} href="/documents" className="group flex items-center gap-4 py-4 first:pt-0 last:pb-0 transition-all">
                                <div className="p-2 rounded-xl bg-[var(--surface-2)] group-hover:bg-[var(--primary)]/10 transition-colors">
                                    <FileText className="h-5 w-5 text-[var(--primary)]" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-bold text-[var(--text)] truncate">{doc.fileName}</p>
                                    <p className="text-xs text-[var(--text-muted)] font-medium">
                                        {format(new Date(doc.createdAt), "d MMMM yyyy")}
                                    </p>
                                </div>
                                <ChevronRight className="h-4 w-4 text-[var(--text-muted)] group-hover:text-[var(--primary)] transition-colors" />
                            </Link>
                        ))}
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

function DashboardAlert({ alert }: { alert: DashboardAlertData }) {
    const isUrgent = alert.severity === "urgent";
    const isInfo = alert.severity === "info";
    const bg = isUrgent ? "var(--danger-soft)" : isInfo ? "var(--info-soft)" : "var(--warning-soft)";
    const border = isUrgent ? "var(--danger-border)" : isInfo ? "var(--info-border)" : "var(--warning-border)";
    const color = isUrgent ? "var(--danger)" : isInfo ? "var(--info)" : "var(--warning)";

    return (
        <div className="flex items-center justify-between gap-3 px-5 py-4 rounded-2xl border text-sm font-bold shadow-sm transition-all hover:shadow-md active:scale-[0.99]"
            style={{ backgroundColor: bg, borderColor: border, color }}>
            <div className="flex items-center gap-3">
                <div className="p-2 rounded-lg" style={{ backgroundColor: bg }}>
                    <AlertTriangle className="h-4 w-4 shrink-0" />
                </div>
                <span>{alert.message}</span>
            </div>
            {alert.action && (
                <Link href={alert.action.href} className="text-xs font-black uppercase tracking-wider underline-offset-4 hover:underline whitespace-nowrap" style={{ color }}>
                    {alert.action.label}
                </Link>
            )}
        </div>
    );
}

export default function DashboardPage() {
    return (
        <React.Suspense fallback={<CardSkeleton />}>
            <DashboardContent />
        </React.Suspense>
    );
}

function ComplianceCard() {
    return (
        <Card className="glass-panel border-none overflow-hidden group">
            <CardContent className="p-5">
                <div className="flex items-center justify-between mb-3">
                    <h3 className="type-overline text-[var(--text-muted)]">Annual Paperwork</h3>
                    <ShieldCheck className="h-4 w-4 text-[var(--primary)]" />
                </div>
                <div className="space-y-3">
                    <div>
                        <h4 className="type-body font-bold text-[var(--text)]">Compensation Fund ROE</h4>
                        <p className="text-xs text-[var(--text-muted)] leading-relaxed">
                            Gather your yearly wage totals and supporting records for the annual ROE submission.
                        </p>
                    </div>
                    <Link href="/compliance/coida/roe">
                        <Button variant="outline" size="sm" className="w-full text-xs font-bold border-[var(--primary)]/20 hover:bg-[var(--primary)]/5 hover:border-[var(--primary)] transition-all h-9 rounded-lg gap-2">
                            Ready in 2 minutes
                            <ArrowRight className="h-3 w-3" />
                        </Button>
                    </Link>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import {
    Cloud,
    Eye,
    FileSpreadsheet,
    FileText,
    FolderOpen,
    HardDrive,
    History,
    Lock,
    Trash2,
    Upload,
} from "lucide-react";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { PageHeader } from "@/components/ui/page-header";
import { FeatureGateCard } from "@/components/ui/feature-gate-card";
import { EmptyState } from "@/components/ui/empty-state";
import { DataTable } from "@/components/ui/data-table";
import { FiltersBar, type FilterChip } from "@/components/ui/filters-bar";
import { DocumentPreview } from "@/components/ui/document-preview";
import { ContractsTab } from "@/components/documents/ContractsTab";
import { useToast } from "@/components/ui/toast";
import { PLANS, type PlanConfig } from "@/config/plans";
import {
    filterRecordsForArchiveWindow,
    getArchiveUpgradeHref,
    getUpgradePlanForArchive,
    isUploadedDocument,
} from "@/lib/archive";
import {
    canUseContractSignedCopyUpload,
    canUseDocumentsHub,
    canUseVaultUploads,
    canUseYearEndSummary,
    getUserPlan,
} from "@/lib/entitlements";
import { generateEmploymentContract, buildContractFileName } from "@/lib/contracts/pdfGenerator";

import {
    deleteDocumentMeta,
    getAllLeaveRecords,
    getAllPayslips,
    getContracts,
    getDocumentFile,
    getDocuments,
    getEmployees,
    getPayPeriods,
    getSettings,
    saveDocumentFile,
    saveDocumentMeta,
    subscribeToDataChanges,
    updateContractStatus,
} from "@/lib/storage";
import { generateYearEndSummaryPdf, getYearEndSummaryStatus } from "@/lib/year-end-summary";
import type { Contract, DocumentMeta, Employee, LeaveRecord, PayPeriod, PayslipInput } from "@/lib/schema";

const TABS = ["Payslips", "Contracts", "Exports", "Vault"] as const;
type Tab = typeof TABS[number];
type VaultCategory = "contracts" | "employee-docs" | "compliance" | "other";

const TAB_TYPE_MAP: Record<Exclude<Tab, "Contracts">, DocumentMeta["type"]> = {
    Payslips: "payslip",
    Exports: "export",
    Vault: "archive",
};

const VAULT_CATEGORIES: Array<{ value: VaultCategory; label: string }> = [
    { value: "contracts", label: "Contracts" },
    { value: "employee-docs", label: "Employee docs" },
    { value: "compliance", label: "Legal" },
    { value: "other", label: "Other" },
];

const VAULT_MAX_FILE_BYTES = 10 * 1024 * 1024;
const ACCEPTED_UPLOAD_EXTENSIONS = [".pdf", ".jpg", ".jpeg", ".png", ".docx"];

function matchesAllowedUpload(file: File): boolean {
    const lowerName = file.name.toLowerCase();
    return ACCEPTED_UPLOAD_EXTENSIONS.some((extension) => lowerName.endsWith(extension));
}

function isPreviewableMimeType(mimeType: string | undefined): boolean {
    if (!mimeType) return false;
    return mimeType === "application/pdf" || mimeType.startsWith("image/");
}

function downloadBlob(blob: Blob, fileName: string) {
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = fileName;
    document.body.appendChild(anchor);
    anchor.click();
    document.body.removeChild(anchor);
    window.setTimeout(() => URL.revokeObjectURL(url), 1000);
}


function buildYearEndSummaryFileName(year: number, householdName?: string) {
    const safeName = (householdName?.trim() || "Employment_Summary").replace(/\s+/g, "_");
    return `${safeName}_${year}.pdf`;
}

function ArchiveBanner({ hiddenCount, href, label }: { hiddenCount: number; href: string; label: string }) {
    if (hiddenCount <= 0) return null;
    return (
        <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <p className="text-sm font-bold text-[var(--text)]">
                        You have {hiddenCount} older record{hiddenCount === 1 ? "" : "s"}.
                    </p>
                    <p className="text-sm text-[var(--text-muted)]">Upgrade to browse your full history in the app.</p>
                </div>
                <Link href={href}>
                    <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">{label}</Button>
                </Link>
            </div>
        </div>
    );
}

export default function DocumentsPage() {
    const { toast } = useToast();
    const router = useRouter();
    const searchParams = useSearchParams();
    const initialTab = (searchParams.get("tab") || "").toLowerCase();
    const defaultTab = initialTab === "contracts"
        ? "Contracts"
        : initialTab === "vault"
            ? "Vault"
            : initialTab === "exports"
                ? "Exports"
                : "Payslips";

    const [activeTab, setActiveTab] = React.useState<Tab>(defaultTab as Tab);
    const [loading, setLoading] = React.useState(true);
    const [documents, setDocuments] = React.useState<DocumentMeta[]>([]);
    const [contracts, setContracts] = React.useState<Contract[]>([]);
    const [employees, setEmployees] = React.useState<Employee[]>([]);
    const [allPayslips, setAllPayslips] = React.useState<PayslipInput[]>([]);
    const [allLeaveRecords, setAllLeaveRecordsState] = React.useState<LeaveRecord[]>([]);
    const [payPeriods, setPayPeriods] = React.useState<PayPeriod[]>([]);
    const [plan, setPlan] = React.useState<PlanConfig>(PLANS.free);
    const [settings, setSettings] = React.useState<Awaited<ReturnType<typeof getSettings>> | null>(null);
    const [search, setSearch] = React.useState("");
    const [empFilter, setEmpFilter] = React.useState<string>("");
    const [vaultCategoryFilter, setVaultCategoryFilter] = React.useState<string>("");
    const [nextVaultCategory, setNextVaultCategory] = React.useState<VaultCategory>("other");
    const [summaryYear, setSummaryYear] = React.useState<number | "">("");
    const [previewDoc, setPreviewDoc] = React.useState<DocumentMeta | null>(null);
    const [previewFileName, setPreviewFileName] = React.useState<string | undefined>(undefined);
    const [previewUrl, setPreviewUrl] = React.useState<string | null>(null);
    const [isGeneratingPreview, setIsGeneratingPreview] = React.useState(false);
    const [isGeneratingSummary, setIsGeneratingSummary] = React.useState(false);
    const [deletingDocumentId, setDeletingDocumentId] = React.useState<string | null>(null);
    const uploadInputRef = React.useRef<HTMLInputElement | null>(null);
    const pdfCache = React.useRef<Record<string, string>>({});
    const [uploadTargetContract, setUploadTargetContract] = React.useState<Contract | null>(null);

    React.useEffect(() => {
        setActiveTab(defaultTab as Tab);
    }, [defaultTab]);

    React.useEffect(() => {
        let active = true;

        async function load() {
            if (!active) return;
            setLoading(true);
            try {
                const [
                    docs,
                    contractRows,
                    employeeRows,
                    userSettings,
                    payslipRows,
                    leaveRows,
                    payPeriodRows,
                ] = await Promise.all([
                    getDocuments(),
                    getContracts(),
                    getEmployees(),
                    getSettings(),
                    getAllPayslips(),
                    getAllLeaveRecords(),
                    getPayPeriods(),
                ]);

                if (!active) return;
                setDocuments(docs);
                setContracts(contractRows);
                setEmployees(employeeRows);
                setSettings(userSettings);
                setPlan(getUserPlan(userSettings));
                setAllPayslips(payslipRows);
                setAllLeaveRecordsState(leaveRows);
                setPayPeriods(payPeriodRows);
            } catch (error) {
                console.error("Failed to load documents hub", error);
            } finally {
                if (active) {
                    setLoading(false);
                }
            }
        }

        void load();
        const unsubscribe = subscribeToDataChanges(load);
        return () => {
            active = false;
            unsubscribe();
        };
    }, []);

    const employeeNameById = React.useMemo(
        () => Object.fromEntries(employees.map((employee) => [employee.id, employee.name])),
        [employees],
    );

    const employeeFilters: FilterChip[] = employees.map((employee) => ({
        key: employee.id,
        label: employee.name,
        active: empFilter === employee.id,
    }));

    const archiveUpgradePlanId = getUpgradePlanForArchive(plan.id);
    const archiveUpgradeHref = getArchiveUpgradeHref(plan.id);
    const archiveUpgradeLabel = archiveUpgradePlanId ? `Upgrade to ${PLANS[archiveUpgradePlanId].label}` : "Upgrade";
    const vaultUpgradeHref = "/upgrade?plan=pro&source=documents.vault";
    const vaultUploadsAllowed = canUseVaultUploads(plan);
    const contractSignedCopyUploadAllowed = canUseContractSignedCopyUpload(plan);
    const yearEndSummaryAllowed = canUseYearEndSummary(plan);

    const payslipDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Payslips),
        [documents],
    );
    const exportDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Exports),
        [documents],
    );
    const vaultDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Vault && document.source === "uploaded"),
        [documents],
    );

    const payslipArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            payslipDocuments.filter((document) => !empFilter || document.employeeId === empFilter),
            plan,
            (document) => document.createdAt,
            { alwaysVisible: isUploadedDocument },
        ),
        [empFilter, payslipDocuments, plan],
    );

    const exportArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            exportDocuments.filter((document) => !empFilter || document.employeeId === empFilter),
            plan,
            (document) => document.createdAt,
            { alwaysVisible: isUploadedDocument },
        ),
        [empFilter, exportDocuments, plan],
    );

    const contractsArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            contracts.filter((contract) => !empFilter || contract.employeeId === empFilter),
            plan,
            (contract) => contract.updatedAt || contract.createdAt,
        ),
        [contracts, empFilter, plan],
    );

    const filteredPayslipDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return payslipArchiveResult.visible.filter((document) => {
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [employeeNameById, payslipArchiveResult.visible, search]);

    const filteredExportDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return exportArchiveResult.visible.filter((document) => {
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [employeeNameById, exportArchiveResult.visible, search]);

    const filteredContracts = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return contractsArchiveResult.visible.filter((contract) => {
            if (!query) return true;
            const employeeName = employeeNameById[contract.employeeId]?.toLowerCase() ?? "";
            return contract.jobTitle.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [contractsArchiveResult.visible, employeeNameById, search]);

    const filteredVaultDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return vaultDocuments.filter((document) => {
            if (empFilter && document.employeeId !== empFilter) return false;
            if (vaultCategoryFilter && document.vaultCategory !== vaultCategoryFilter) return false;
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [empFilter, employeeNameById, search, vaultCategoryFilter, vaultDocuments]);

    const availableSummaryYears = React.useMemo(
        () => getYearEndSummaryStatus(payPeriods, new Date().getFullYear()).availableYears,
        [payPeriods],
    );

    React.useEffect(() => {
        if (!summaryYear && availableSummaryYears.length > 0) {
            setSummaryYear(availableSummaryYears[0]);
        }
    }, [availableSummaryYears, summaryYear]);

    const selectedYearStatus = React.useMemo(
        () => summaryYear ? getYearEndSummaryStatus(payPeriods, Number(summaryYear)) : null,
        [payPeriods, summaryYear],
    );

    const handlePreview = async (doc: DocumentMeta) => {
        setPreviewDoc(doc);
        setPreviewFileName(doc.fileName);

        if (pdfCache.current[doc.id]) {
            const cachedUrl = pdfCache.current[doc.id];

            // For PDFs, open directly in a new tab instead of the side-panel viewer
            if ((doc.mimeType || "").startsWith("application/pdf")) {
                if (typeof window !== "undefined") {
                    window.open(cachedUrl, "_blank", "noopener,noreferrer");
                }
                return;
            }

            setPreviewUrl(cachedUrl);
            return;
        }

        setIsGeneratingPreview(true);

        try {
            if (doc.type === "payslip" && doc.employeeId) {
                router.push(`/preview?payslipId=${doc.id}&empId=${doc.employeeId}`);
                return;
            }

            const blob = await getDocumentFile(doc.id);
            if (!blob) {
                throw new Error("That file is not available yet.");
            }

            const mimeType = blob.type || doc.mimeType || "application/octet-stream";

            // PDFs: open in a proper browser tab instead of the cramped side panel
            if (mimeType === "application/pdf") {
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                if (typeof window !== "undefined") {
                    window.open(url, "_blank", "noopener,noreferrer");
                }
                return;
            }

            // Images and other inline-previewable types keep using the in-app preview panel
            if (isPreviewableMimeType(mimeType)) {
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                setPreviewUrl(url);
                return;
            }

            setPreviewDoc(null);
            setPreviewFileName(undefined);
            downloadBlob(blob, doc.fileName);
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not open that document.", "error");
            setPreviewDoc(null);
            setPreviewFileName(undefined);
        } finally {
            setIsGeneratingPreview(false);
        }
    };

    const openContractPreview = (contract: Contract) => {
        router.push(`/contracts/${contract.id}/preview`);
    };

    const downloadContract = async (contract: Contract) => {
        if (!settings) return;
        const employee = employees.find((entry) => entry.id === contract.employeeId);
        if (!employee) return;
        const pdfBytes = await generateEmploymentContract(contract, employee, settings);
        const blob = new Blob([new Uint8Array(pdfBytes)], { type: "application/pdf" });
        downloadBlob(blob, buildContractFileName(contract, employee));

        if (contract.status === "draft") {
            await updateContractStatus(contract.id, "awaiting_signed_copy");
        }
    };

    const handleMarkFinal = async (contract: Contract) => {
        try {
            await updateContractStatus(contract.id, "final", { finalizedAt: new Date().toISOString() });
            toast("Contract marked as final.", "success");
        } catch {
            toast("Could not update contract status.", "error");
        }
    };

    const handleContractUploadClick = (contract: Contract) => {
        if (!contractSignedCopyUploadAllowed) return;
        setUploadTargetContract(contract);
        uploadInputRef.current?.click();
    };

    const handleVaultUploadClick = () => {
        if (!vaultUploadsAllowed) {
            router.push(vaultUpgradeHref);
            return;
        }
        setUploadTargetContract(null);
        uploadInputRef.current?.click();
    };

    const handleSignedDocumentSelected = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        const targetContract = uploadTargetContract;
        event.target.value = "";

        if (!file) return;

        if (targetContract && file.type !== "application/pdf") {
            toast("Signed contracts must be uploaded as PDF files.", "error");
            return;
        } else if (!targetContract && !matchesAllowedUpload(file)) {
            toast("Upload a PDF, JPG, PNG, or DOCX file.", "error");
            return;
        }

        if (file.size > VAULT_MAX_FILE_BYTES) {
            toast("Files must be 10 MB or smaller.", "error");
            return;
        }

        try {
            const id = crypto.randomUUID();
            const createdAt = new Date().toISOString();

            if (targetContract) {
                if (!contractSignedCopyUploadAllowed) {
                    router.push("/upgrade?plan=standard&source=contracts.signedUploads");
                    return;
                }

                const employee = employees.find((entry) => entry.id === targetContract.employeeId);
                const nextDocument: DocumentMeta = {
                    id,
                    householdId: employee?.householdId ?? settings?.activeHouseholdId ?? "default",
                    type: "archive",
                    employeeId: employee?.id,
                    periodId: targetContract.id,
                    fileName: file.name,
                    mimeType: file.type || "application/octet-stream",
                    source: "uploaded",
                    vaultCategory: "contracts",
                    sizeBytes: file.size,
                    createdAt,
                };

                await saveDocumentFile(id, file);
                await saveDocumentMeta(nextDocument);
                await updateContractStatus(targetContract.id, "signed_copy_stored", { signedDocumentId: id });
                setDocuments((current) => [nextDocument, ...current]);
                toast("Signed copy saved.", "success");
                return;
            }

            const nextDocument: DocumentMeta = {
                id,
                householdId: settings?.activeHouseholdId ?? "default",
                type: "archive",
                fileName: file.name,
                mimeType: file.type || "application/octet-stream",
                source: "uploaded",
                vaultCategory: nextVaultCategory,
                sizeBytes: file.size,
                createdAt,
            };

            await saveDocumentFile(id, file);
            await saveDocumentMeta(nextDocument);
            setDocuments((current) => [nextDocument, ...current]);
            toast("Document uploaded.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not save that file.", "error");
        } finally {
            setUploadTargetContract(null);
        }
    };

    const handleDeleteVaultDocument = async (document: DocumentMeta) => {
        if (!vaultUploadsAllowed) return;
        if (typeof window !== "undefined" && !window.confirm(`Delete ${document.fileName}?`)) {
            return;
        }

        try {
            setDeletingDocumentId(document.id);
            await deleteDocumentMeta(document.id);
            setDocuments((current) => current.filter((entry) => entry.id !== document.id));
            if (previewDoc?.id === document.id) {
                if (previewUrl) URL.revokeObjectURL(previewUrl);
                setPreviewDoc(null);
                setPreviewFileName(undefined);
                setPreviewUrl(null);
            }
            toast("Document removed from Vault.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not delete that file.", "error");
        } finally {
            setDeletingDocumentId(null);
        }
    };

    const handleGenerateYearEndSummary = async () => {
        if (!summaryYear || !yearEndSummaryAllowed || !settings) return;

        try {
            setIsGeneratingSummary(true);
            const pdfBytes = await generateYearEndSummaryPdf({
                year: Number(summaryYear),
                householdName: settings.employerName || "Employment Summary",
                employees,
                payslips: allPayslips,
                leaveRecords: allLeaveRecords,
                payPeriods,
            });

            const id = crypto.randomUUID();
            const createdAt = new Date().toISOString();
            const fileName = buildYearEndSummaryFileName(Number(summaryYear), settings.employerName || "Employment Summary");
            const blob = new Blob([new Uint8Array(pdfBytes).buffer], { type: "application/pdf" });
            const nextDocument: DocumentMeta = {
                id,
                householdId: settings.activeHouseholdId ?? "default",
                type: "export",
                fileName,
                mimeType: "application/pdf",
                source: "generated",
                createdAt,
                sizeBytes: blob.size,
            };

            await saveDocumentFile(id, blob);
            await saveDocumentMeta(nextDocument);
            setDocuments((current) => [nextDocument, ...current]);
            toast("Year-end summary saved to Exports.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not generate the year-end summary.", "error");
        } finally {
            setIsGeneratingSummary(false);
        }
    };

    const closePreview = React.useCallback(() => {
        if (previewUrl) URL.revokeObjectURL(previewUrl);
        setPreviewDoc(null);
        setPreviewFileName(undefined);
        setPreviewUrl(null);
    }, [previewUrl]);

    const hasAnyContent = documents.length > 0 || contracts.length > 0;

    if (loading) {
        return (
            <>
                <PageHeader title="Documents" subtitle="Payslips, contracts, exports, and vault history" />
                <EmptyState
                    title="Loading documents"
                    description="Pulling together your payslips, contracts, exports, and stored records."
                    icon={FolderOpen}
                />
            </>
        );
    }

    if (!canUseDocumentsHub(plan)) {
        return (
            <>
                <PageHeader title="Documents" subtitle="Payslips, contracts, exports, and vault history" />
                <FeatureGateCard
                    title="Documents hub is available on Standard and Pro"
                    description="Free keeps payroll and payslips simple for one worker. Upgrade for contracts, document uploads, exports, and longer record access."
                />
            </>
        );
    }

    return (
        <>
            <PageHeader
                title="Documents"
                subtitle="Payslips, contracts, exports, and vault history in one place"
                actions={activeTab === "Vault" ? (
                    vaultUploadsAllowed ? (
                        <Button
                            type="button"
                            className="gap-2 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold h-10 px-4 text-sm"
                            onClick={handleVaultUploadClick}
                        >
                            <Upload className="h-4 w-4 shrink-0" />
                            <span className="hidden sm:inline">Upload Document</span>
                            <span className="sm:hidden">Upload</span>
                        </Button>
                    ) : (
                        <Link href={vaultUpgradeHref}>
                            <Button variant="outline" className="gap-2 font-bold">
                                <Lock className="h-4 w-4" /> Upgrade to Pro
                            </Button>
                        </Link>
                    )
                ) : undefined}
            />

            <input
                ref={uploadInputRef}
                type="file"
                accept=".pdf,.jpg,.jpeg,.png,.docx"
                className="hidden"
                onChange={handleSignedDocumentSelected}
            />

            <div className="ultrawide-grid">
                <div className="ultrawide-main space-y-6">
                    <div className="flex items-center border-b border-[var(--border)] -mx-4 overflow-x-auto px-4 no-scrollbar lg:mx-0 lg:px-0">
                        {TABS.map((tab) => (
                            <button
                                key={tab}
                                type="button"
                                onClick={() => setActiveTab(tab)}
                                className={`whitespace-nowrap border-b-2 px-3 sm:px-4 py-3 text-sm font-bold transition-colors min-h-[44px] ${activeTab === tab ? "border-[var(--primary)] text-[var(--primary)]" : "border-transparent text-[var(--text-muted)] hover:text-[var(--text)]"}`}
                            >
                                {tab}
                            </button>
                        ))}
                    </div>

                    {hasAnyContent && activeTab !== "Contracts" && (
                        <FiltersBar
                            searchPlaceholder={`Search ${activeTab.toLowerCase()}...`}
                            searchValue={search}
                            onSearchChange={setSearch}
                            filters={employeeFilters}
                            onFilterToggle={(key) => setEmpFilter((current) => current === key ? "" : key)}
                        />
                    )}

                    {activeTab === "Contracts" && filteredContracts.length > 0 && (
                        <div className="rounded-full border border-orange-200 bg-orange-50 px-3 py-1.5 text-xs text-orange-800">
                            <strong>Review before signing:</strong>&nbsp;Templates are starting points. Verify with a labour lawyer if unsure.
                        </div>
                    )}

                    {activeTab === "Vault" && (
                        <Card className="glass-panel border-none">
                            <CardContent className="space-y-4 p-5">
                                <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                                    <div>
                                        <p className="text-[10px] font-black uppercase tracking-[0.16em] text-[var(--text-muted)]">Vault categories</p>
                                        <p className="mt-1 text-sm text-[var(--text-muted)]">Store signed contracts, ID copies, and other supporting records in one place.</p>
                                    </div>
                                    {vaultUploadsAllowed && (
                                        <label className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            New uploads:
                                            <select
                                                value={nextVaultCategory}
                                                onChange={(event) => setNextVaultCategory(event.target.value as VaultCategory)}
                                                className="rounded-xl border border-[var(--border)] bg-[var(--surface-1)] px-3 py-2 text-sm text-[var(--text)]"
                                            >
                                                {VAULT_CATEGORIES.map((category) => (
                                                    <option key={category.value} value={category.value}>
                                                        {category.label}
                                                    </option>
                                                ))}
                                            </select>
                                        </label>
                                    )}
                                </div>

                                <div className="flex flex-wrap gap-2">
                                    <button
                                        type="button"
                                        onClick={() => setVaultCategoryFilter("")}
                                        className={`rounded-full border px-3 py-1.5 text-[11px] font-bold uppercase tracking-wide ${vaultCategoryFilter === "" ? "border-[var(--primary)] bg-[var(--primary)] text-white" : "border-[var(--border)] text-[var(--text-muted)]"}`}
                                    >
                                        All files
                                    </button>
                                    {VAULT_CATEGORIES.map((category) => (
                                        <button
                                            key={category.value}
                                            type="button"
                                            onClick={() => setVaultCategoryFilter((current) => current === category.value ? "" : category.value)}
                                            className={`rounded-full border px-3 py-1.5 text-[11px] font-bold uppercase tracking-wide ${vaultCategoryFilter === category.value ? "border-[var(--primary)] bg-[var(--primary)] text-white" : "border-[var(--border)] text-[var(--text-muted)]"}`}
                                        >
                                            {category.label}
                                        </button>
                                    ))}
                                </div>

                                {!vaultUploadsAllowed && (
                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
                                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                                            <div>
                                                <p className="text-sm font-bold text-[var(--text)]">Upload anything to the Vault on Pro</p>
                                                <p className="text-sm text-[var(--text-muted)]">Standard keeps signed contract copies active on contract pages. Pro unlocks general document uploads here.</p>
                                            </div>
                                            <Link href={vaultUpgradeHref}>
                                                <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">Upgrade to Pro</Button>
                                            </Link>
                                        </div>
                                    </div>
                                )}

                                {(vaultUploadsAllowed) && (
                                    <p className="text-xs text-[var(--text-muted)]">Your files are stored on this device.</p>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {activeTab === "Exports" && plan.id !== "free" && (
                        <Card className="glass-panel border-none">
                            <CardContent className="space-y-4 p-5">
                                <div>
                                    <p className="text-[10px] font-black uppercase tracking-[0.16em] text-[var(--text-muted)]">Year-end summary</p>
                                    <h2 className="mt-1 text-lg font-black text-[var(--text)]">One PDF for the full year</h2>
                                    <p className="mt-1 text-sm text-[var(--text-muted)]">Summarise finalised payroll totals and leave taken for each worker over one calendar year.</p>
                                </div>

                                {yearEndSummaryAllowed ? (
                                    <>
                                        {availableSummaryYears.length === 0 ? (
                                            <p className="text-sm text-[var(--text-muted)]">Finalise a payroll month first, then you can generate a year-end summary here.</p>
                                        ) : (
                                            <>
                                                <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
                                                    <label className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                                        Year
                                                        <select
                                                            value={summaryYear}
                                                            onChange={(event) => setSummaryYear(Number(event.target.value))}
                                                            className="rounded-xl border border-[var(--border)] bg-[var(--surface-1)] px-3 py-2 text-sm text-[var(--text)]"
                                                        >
                                                            {availableSummaryYears.map((year) => (
                                                                <option key={year} value={year}>
                                                                    {year}
                                                                </option>
                                                            ))}
                                                        </select>
                                                    </label>
                                                    <Button
                                                        type="button"
                                                        onClick={handleGenerateYearEndSummary}
                                                        disabled={isGeneratingSummary || !summaryYear}
                                                        className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]"
                                                    >
                                                        {isGeneratingSummary ? "Generating..." : "Generate PDF"}
                                                    </Button>
                                                </div>
                                                {selectedYearStatus && selectedYearStatus.unlockedMonthCount > 0 && (
                                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-3 text-sm text-[var(--text)]">
                                                        {selectedYearStatus.unlockedMonthCount} month{selectedYearStatus.unlockedMonthCount === 1 ? "" : "s"} in {summaryYear} have not been finalised yet. The summary will only include finalised months.
                                                    </div>
                                                )}
                                            </>
                                        )}
                                    </>
                                ) : (
                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
                                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                                            <div>
                                                <p className="text-sm font-bold text-[var(--text)]">Year-end summaries are available on Pro</p>
                                                <p className="text-sm text-[var(--text-muted)]">Keep one ready-to-share PDF for your records or your tax practitioner.</p>
                                            </div>
                                            <Link href={vaultUpgradeHref}>
                                                <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">Upgrade to Pro</Button>
                                            </Link>
                                        </div>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {activeTab === "Contracts" ? (
                        <ContractsTab
                            contracts={filteredContracts}
                            employees={employees}
                            documents={documents}
                            hiddenCount={contractsArchiveResult.hiddenCount}
                            archiveUpgradeHref={archiveUpgradeHref}
                            archiveUpgradeLabel={archiveUpgradeLabel}
                            openContractPreview={openContractPreview}
                            downloadContract={downloadContract}
                            handleContractUploadClick={handleContractUploadClick}
                            handlePreview={handlePreview}
                            handleMarkFinal={handleMarkFinal}
                            toast={toast}
                        />
                    ) : activeTab === "Payslips" ? (
                        filteredPayslipDocuments.length === 0 ? (
                            <EmptyState
                                title="No payslips yet"
                                description="Payslip PDFs will appear here automatically after you finalise your first pay period."
                                icon={FileText}
                                actionLabel={employees.length === 0 ? "Add your first employee" : "Run payroll"}
                                actionHref={employees.length === 0 ? "/employees/new" : "/payroll"}
                            />
                        ) : (
                            <>
                                <DataTable<DocumentMeta>
                                    data={filteredPayslipDocuments}
                                    keyField={(doc) => doc.id}
                                    emptyMessage="No payslips match your filters."
                                    columns={[
                                        {
                                            key: "fileName",
                                            label: "File",
                                            render: (doc) => (
                                                <div className="flex items-center gap-3">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileText className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <span className="type-body-bold text-[var(--text)]">{doc.fileName}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "employee",
                                            label: "Employee",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{doc.employeeId ? employeeNameById[doc.employeeId] ?? "Unknown" : "-"}</span>,
                                        },
                                        {
                                            key: "storage",
                                            label: "Storage",
                                            render: (doc) => (
                                                <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                                    <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />
                                                    <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">This device</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "date",
                                            label: "Added",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                        },
                                        {
                                            key: "actions",
                                            label: "",
                                            align: "right",
                                            render: (doc) => (
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="h-9 px-3 gap-2 rounded-full border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                    onClick={() => void handlePreview(doc)}
                                                >
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                    <span className="text-xs font-bold">Preview</span>
                                                </Button>
                                            ),
                                        },
                                    ]}
                                    renderCard={(doc) => (
                                        <Card className="glass-panel border-none">
                                            <CardContent className="p-3 space-y-2">
                                                <div className="flex items-center gap-3 min-w-0">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileText className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <div className="min-w-0 flex-1">
                                                        <p className="text-sm font-bold text-[var(--text)] truncate">{doc.fileName}</p>
                                                        <p className="text-xs text-[var(--text-muted)]">{doc.employeeId ? employeeNameById[doc.employeeId] ?? "Unknown" : "-"} ┬╖ {format(new Date(doc.createdAt), "d MMM yyyy")}</p>
                                                    </div>
                                                </div>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="w-full h-9 gap-2 rounded-xl border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                    onClick={() => void handlePreview(doc)}
                                                >
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                    <span className="text-xs font-bold">Preview</span>
                                                </Button>
                                            </CardContent>
                                        </Card>
                                    )}
                                />
                                <ArchiveBanner hiddenCount={payslipArchiveResult.hiddenCount} href={archiveUpgradeHref} label={archiveUpgradeLabel} />
                            </>
                        )
                    ) : activeTab === "Exports" ? (
                        filteredExportDocuments.length === 0 ? (
                            <EmptyState
                                title="No exports available"
                                description="Official documents like Year-End Summaries and UIF declarations will be generated here. Finalise a payroll month to unlock your first export."
                                icon={FileSpreadsheet}
                            />
                        ) : (
                            <>
                                <DataTable<DocumentMeta>
                                    data={filteredExportDocuments}
                                    keyField={(doc) => doc.id}
                                    emptyMessage="No exports match your filters."
                                    columns={[
                                        {
                                            key: "fileName",
                                            label: "File",
                                            render: (doc) => (
                                                <div className="flex items-center gap-3">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileSpreadsheet className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <span className="type-body-bold text-[var(--text)]">{doc.fileName}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "storage",
                                            label: "Storage",
                                            render: (doc) => (
                                                <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                                    <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />
                                                    <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">This device</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "date",
                                            label: "Added",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                        },
                                        {
                                            key: "actions",
                                            label: "",
                                            align: "right",
                                            render: (doc) => (
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="h-9 px-3 gap-2 rounded-full border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                    onClick={() => void handlePreview(doc)}
                                                >
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                    <span className="text-xs font-bold">Preview</span>
                                                </Button>
                                            ),
                                        },
                                    ]}
                                    renderCard={(doc) => (
                                        <Card className="glass-panel border-none">
                                            <CardContent className="p-3 space-y-2">
                                                <div className="flex items-center gap-3 min-w-0">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileSpreadsheet className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <div className="min-w-0 flex-1">
                                                        <p className="text-sm font-bold text-[var(--text)] truncate">{doc.fileName}</p>
                                                        <p className="text-xs text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</p>
                                                    </div>
                                                </div>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="w-full h-9 gap-2 rounded-xl border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                    onClick={() => void handlePreview(doc)}
                                                >
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                    <span className="text-xs font-bold">Preview</span>
                                                </Button>
                                            </CardContent>
                                        </Card>
                                    )}
                                />
                                <ArchiveBanner hiddenCount={exportArchiveResult.hiddenCount} href={archiveUpgradeHref} label={archiveUpgradeLabel} />
                            </>
                        )
                    ) : filteredVaultDocuments.length === 0 ? (
                        vaultUploadsAllowed ? (
                            <div className="rounded-2xl border border-dashed border-[var(--border)] bg-[var(--surface-1)] p-10 text-center">
                                <FolderOpen className="mx-auto mb-3 h-10 w-10 text-[var(--text-muted)]" strokeWidth={1.5} />
                                <p className="text-sm font-bold text-[var(--text)]">Secure Document Vault</p>
                                <p className="mt-1 text-sm text-[var(--text-muted)]">A safe place to upload and store external employee records. Keep ID copies, sick notes, and compliance forms organised here.</p>
                                <Button className="mt-4 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]" onClick={handleVaultUploadClick}>
                                    Upload document
                                </Button>
                            </div>
                        ) : (
                            <FeatureGateCard
                                title="Secure Document Vault"
                                description="Vault uploads are available on Pro. A safe place to upload and store external employee records. Keep ID copies, sick notes, and compliance forms organised here."
                                ctaLabel="Upgrade to Pro"
                                href={vaultUpgradeHref}
                                eyebrow="Pro"
                                benefits={[
                                    "Private document vault with encrypted sync",
                                    "All uploaded files stay in one place",
                                    "Upload general household employment paperwork",
                                ]}
                            />
                        )
                    ) : (
                        <DataTable<DocumentMeta>
                            data={filteredVaultDocuments}
                            keyField={(doc) => doc.id}
                            emptyMessage="No Vault files match your filters."
                            columns={[
                                {
                                    key: "fileName",
                                    label: "File",
                                    render: (doc) => (
                                        <div className="flex items-center gap-3">
                                            <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                <FileText className="h-4 w-4 text-[var(--primary)]" />
                                            </div>
                                            <div>
                                                <p className="type-body-bold text-[var(--text)]">{doc.fileName}</p>
                                                <p className="text-xs text-[var(--text-muted)]">{VAULT_CATEGORIES.find((category) => category.value === doc.vaultCategory)?.label ?? "Other"}</p>
                                            </div>
                                        </div>
                                    ),
                                },
                                {
                                    key: "employee",
                                    label: "Employee",
                                    render: (doc) => <span className="type-body text-[var(--text-muted)]">{doc.employeeId ? employeeNameById[doc.employeeId] ?? "Unknown" : "-"}</span>,
                                },
                                {
                                    key: "storage",
                                    label: "Storage",
                                    render: (doc) => (
                                        <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                            <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />
                                            <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">This device</span>
                                        </div>
                                    ),
                                },
                                {
                                    key: "date",
                                    label: "Added",
                                    render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                },
                                {
                                    key: "actions",
                                    label: "",
                                    align: "right",
                                    render: (doc) => (
                                        <div className="flex items-center justify-end gap-2">
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                className="h-9 px-3 gap-2 rounded-full border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                onClick={() => void handlePreview(doc)}
                                            >
                                                <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                <span className="text-xs font-bold">Preview</span>
                                            </Button>
                                            {vaultUploadsAllowed ? (
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="h-9 gap-2 rounded-full border px-3 text-[var(--danger)] hover:bg-[var(--danger-soft)]"
                                                    style={{ borderColor: "var(--danger-border)" }}
                                                    disabled={deletingDocumentId === doc.id}
                                                    onClick={() => void handleDeleteVaultDocument(doc)}
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                    <span className="text-xs font-bold">Delete</span>
                                                </Button>
                                            ) : null}
                                        </div>
                                    ),
                                        },
                                    ]}
                                    renderCard={(doc) => (
                                        <Card className="glass-panel border-none">
                                            <CardContent className="p-3 space-y-2">
                                                <div className="flex items-center gap-3 min-w-0">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileText className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <div className="min-w-0 flex-1">
                                                        <p className="text-sm font-bold text-[var(--text)] truncate">{doc.fileName}</p>
                                                        <p className="text-xs text-[var(--text-muted)]">{VAULT_CATEGORIES.find((c) => c.value === doc.vaultCategory)?.label ?? "Other"} ┬╖ {format(new Date(doc.createdAt), "d MMM yyyy")}</p>
                                                    </div>
                                                </div>
                                                <div className="flex gap-2">
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        className="flex-1 h-9 gap-2 rounded-xl border border-[var(--border)] hover:bg-[var(--surface-2)]"
                                                        onClick={() => void handlePreview(doc)}
                                                    >
                                                        <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                        <span className="text-xs font-bold">Preview</span>
                                                    </Button>
                                                    {vaultUploadsAllowed ? (
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            className="flex-1 h-9 gap-2 rounded-xl border border-red-200 text-red-700 hover:text-red-800 hover:bg-red-50"
                                                            disabled={deletingDocumentId === doc.id}
                                                            onClick={() => void handleDeleteVaultDocument(doc)}
                                                        >
                                                            <Trash2 className="h-4 w-4" />
                                                            <span className="text-xs font-bold">Delete</span>
                                                        </Button>
                                                    ) : null}
                                                </div>
                                            </CardContent>
                                        </Card>
                                    )}
                                />
                    )}
                </div>
                {hasAnyContent && (
                    <aside className="ultrawide-panel hidden 2xl:block">
                        <Card className="glass-panel sticky top-0 border-none p-5">
                            <div className="space-y-4">
                                <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                    <History className="h-4 w-4 text-[var(--primary)]" />
                                    One documentation hub
                                </div>
                                <p className="text-sm text-[var(--text-muted)]">
                                    This screen keeps payslips, contracts, exports, and uploaded records together so nothing feels split across the app.
                                </p>
                                {activeTab === "Contracts" && (
                                    <div className="space-y-2 rounded-2xl border border-[var(--border)] bg-[var(--surface-2)]/60 p-4">
                                        <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            <Upload className="h-4 w-4 text-[var(--primary)]" />
                                            Signed copy workflow
                                        </div>
                                        <p className="text-sm text-[var(--text-muted)]">
                                            Use the contract draft first. After you print and sign the final version, upload the signed copy here so it stays with the rest of the employee record.
                                        </p>
                                    </div>
                                )}
                                {activeTab === "Vault" && (
                                    <div className="space-y-2 rounded-2xl border border-[var(--border)] bg-[var(--surface-2)]/60 p-4">
                                        <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            <Cloud className="h-4 w-4 text-[var(--primary)]" />
                                            Vault storage
                                        </div>
                                        <p className="text-sm text-[var(--text-muted)]">
                                            Existing uploaded files always stay visible here. Pro unlocks new uploads for contracts, employee paperwork, and legal records.
                                        </p>
                                    </div>
                                )}
                            </div>
                        </Card>
                    </aside>
                )}
            </div>

            {isGeneratingPreview && (
                <div className="fixed bottom-6 right-6 z-50 flex items-center justify-center rounded-full bg-[var(--primary)] p-4 text-white shadow-2xl animate-pulse">
                    Generating preview...
                </div>
            )}

            {previewUrl && (
                <DocumentPreview
                    url={previewUrl}
                    fileName={previewFileName ?? previewDoc?.fileName}
                    onClose={closePreview}
                    onDownload={() => {
                        const anchor = document.createElement("a");
                        anchor.href = previewUrl;
                        anchor.download = previewFileName ?? previewDoc?.fileName ?? "document.pdf";
                        document.body.appendChild(anchor);
                        anchor.click();
                        document.body.removeChild(anchor);
                    }}
                />
            )}
        </>
    );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { format } from "date-fns";
import { Cloud, Eye, FileText, FolderOpen, HardDrive, ScrollText, Trash2, Upload } from "lucide-react";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import { EmptyState } from "@/components/ui/empty-state";
import { FeatureGateCard } from "@/components/ui/feature-gate-card";
import { DocumentPreview } from "@/components/ui/document-preview";
import { ContractRow } from "@/components/documents/ContractRow";
import { useToast } from "@/components/ui/toast";
import { canUseContractSignedCopyUpload, canUseVaultUploads } from "@/lib/entitlements";
import { deleteDocumentMeta, getDocumentFile, saveDocumentFile, saveDocumentMeta, updateContractStatus } from "@/lib/storage";
import { buildContractFileName, generateEmploymentContract } from "@/lib/contracts/pdfGenerator";
import type { Contract, DocumentMeta, Employee, EmployerSettings } from "@/lib/schema";
import type { PlanConfig } from "@/config/plans";
import { useRouter } from "next/navigation";

function downloadBlob(blob: Blob, fileName: string) {
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = fileName;
    document.body.appendChild(anchor);
    anchor.click();
    document.body.removeChild(anchor);
    window.setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function isPreviewableMimeType(mimeType: string | undefined): boolean {
    if (!mimeType) return false;
    return mimeType === "application/pdf" || mimeType.startsWith("image/");
}

const VAULT_MAX_FILE_BYTES = 10 * 1024 * 1024;
const ACCEPTED_UPLOAD_EXTENSIONS = [".pdf", ".jpg", ".jpeg", ".png", ".docx"];

function matchesAllowedUpload(file: File): boolean {
    const lowerName = file.name.toLowerCase();
    return ACCEPTED_UPLOAD_EXTENSIONS.some((extension) => lowerName.endsWith(extension));
}

type Tab = "Payslips" | "Contracts" | "Legal" | "Other";
type VaultCategory = "contracts" | "employee-docs" | "compliance" | "other";

const VAULT_CATEGORIES: Array<{ value: VaultCategory; label: string }> = [
    { value: "contracts", label: "Contracts" },
    { value: "employee-docs", label: "Employee docs" },
    { value: "compliance", label: "Legal" },
    { value: "other", label: "Other" },
];

export function EmployeeDocumentsTab({
    employee,
    contracts,
    documents,
    settings,
    currentPlan,
    onDocumentsChange,
}: {
    employee: Employee;
    contracts: Contract[];
    documents: DocumentMeta[];
    settings: EmployerSettings;
    currentPlan: PlanConfig;
    onDocumentsChange?: () => void;
}) {
    const { toast } = useToast();
    const router = useRouter();
    const [activeTab, setActiveTab] = React.useState<Tab>("Payslips");
    const [search, setSearch] = React.useState("");
    const [uploadContext, setUploadContext] = React.useState<"contracts" | "legal" | "other" | null>(null);
    
    const [previewDoc, setPreviewDoc] = React.useState<DocumentMeta | null>(null);
    const [previewFileName, setPreviewFileName] = React.useState<string | undefined>(undefined);
    const [previewUrl, setPreviewUrl] = React.useState<string | null>(null);
    const [isGeneratingPreview, setIsGeneratingPreview] = React.useState(false);
    const [deletingDocumentId, setDeletingDocumentId] = React.useState<string | null>(null);
    
    const uploadInputRef = React.useRef<HTMLInputElement | null>(null);
    const pdfCache = React.useRef<Record<string, string>>({});
    const [uploadTargetContract, setUploadTargetContract] = React.useState<Contract | null>(null);

    const vaultUploadsAllowed = canUseVaultUploads(currentPlan);
    const contractSignedCopyUploadAllowed = canUseContractSignedCopyUpload(currentPlan);
    const vaultUpgradeHref = "/upgrade?plan=pro";

    const employeePayslipDocuments = React.useMemo(
        () =>
            documents.filter(
                (doc) => doc.type === "payslip" && doc.employeeId === employee.id,
            ),
        [documents, employee.id],
    );

    const employeeVaultDocuments = React.useMemo(
        () =>
            documents.filter(
                (doc) => doc.type === "archive" && doc.source === "uploaded" && doc.employeeId === employee.id,
            ),
        [documents, employee.id],
    );

    const legalDocuments = React.useMemo(
        () => employeeVaultDocuments.filter((doc) => doc.vaultCategory === "compliance"),
        [employeeVaultDocuments],
    );

    const otherDocuments = React.useMemo(
        () =>
            employeeVaultDocuments.filter(
                (doc) => doc.vaultCategory !== "compliance" && doc.vaultCategory !== "contracts",
            ),
        [employeeVaultDocuments],
    );

    const filteredContracts = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        if (!query) return contracts;
        return contracts.filter((contract) =>
            contract.jobTitle.toLowerCase().includes(query),
        );
    }, [contracts, search]);

    const filteredPayslipDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        if (!query) return employeePayslipDocuments;
        return employeePayslipDocuments.filter((doc) =>
            doc.fileName.toLowerCase().includes(query),
        );
    }, [employeePayslipDocuments, search]);

    const filteredLegalDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        if (!query) return legalDocuments;
        return legalDocuments.filter((doc) =>
            doc.fileName.toLowerCase().includes(query),
        );
    }, [legalDocuments, search]);

    const filteredOtherDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        if (!query) return otherDocuments;
        return otherDocuments.filter((doc) =>
            doc.fileName.toLowerCase().includes(query),
        );
    }, [otherDocuments, search]);

    const handlePreview = async (doc: DocumentMeta) => {
        setPreviewDoc(doc);
        setPreviewFileName(doc.fileName);

        if (pdfCache.current[doc.id]) {
            const cachedUrl = pdfCache.current[doc.id];

            if ((doc.mimeType || "").startsWith("application/pdf")) {
                if (typeof window !== "undefined") {
                    window.open(cachedUrl, "_blank", "noopener,noreferrer");
                }
                return;
            }

            setPreviewUrl(cachedUrl);
            return;
        }

        setIsGeneratingPreview(true);

        try {
            const blob = await getDocumentFile(doc.id);
            if (!blob) {
                throw new Error("That file is not available yet.");
            }

            const mimeType = blob.type || doc.mimeType || "application/octet-stream";

            if (mimeType === "application/pdf") {
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                if (typeof window !== "undefined") {
                    window.open(url, "_blank", "noopener,noreferrer");
                }
                return;
            }

            if (isPreviewableMimeType(mimeType)) {
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                setPreviewUrl(url);
                return;
            }

            setPreviewDoc(null);
            setPreviewFileName(undefined);
            downloadBlob(blob, doc.fileName);
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not open that document.", "error");
            setPreviewDoc(null);
            setPreviewFileName(undefined);
        } finally {
            setIsGeneratingPreview(false);
        }
    };

    const closePreview = React.useCallback(() => {
        if (previewUrl) URL.revokeObjectURL(previewUrl);
        setPreviewDoc(null);
        setPreviewFileName(undefined);
        setPreviewUrl(null);
    }, [previewUrl]);

    const openContractPreview = (contract: Contract) => {
        router.push(`/contracts/${contract.id}/preview`);
    };

    const downloadContract = async (contract: Contract) => {
        if (!settings) return;
        const pdfBytes = await generateEmploymentContract(contract, employee, settings);
        const blob = new Blob([new Uint8Array(pdfBytes)], { type: "application/pdf" });
        downloadBlob(blob, buildContractFileName(contract, employee));

        if (contract.status === "draft") {
            await updateContractStatus(contract.id, "awaiting_signed_copy");
            if (onDocumentsChange) onDocumentsChange();
        }
    };

    const handleMarkFinal = async (contract: Contract) => {
        try {
            await updateContractStatus(contract.id, "final", { finalizedAt: new Date().toISOString() });
            toast("Contract marked as final.", "success");
            if (onDocumentsChange) onDocumentsChange();
        } catch {
            toast("Could not update contract status.", "error");
        }
    };

    const handleDeleteContract = async (contract: Contract) => {
        if (typeof window !== "undefined" && !window.confirm("Delete this contract? This cannot be undone.")) {
            return;
        }
        try {
            const { deleteContract } = await import("@/lib/storage");
            await deleteContract(contract.id);
            if (onDocumentsChange) onDocumentsChange();
            toast("Contract deleted.", "success");
        } catch {
            toast("Could not delete contract.", "error");
        }
    };

    const handleContractUploadClick = (contract: Contract) => {
        if (!contractSignedCopyUploadAllowed) return;
        setUploadTargetContract(contract);
        setUploadContext("contracts");
        uploadInputRef.current?.click();
    };

    const handleLegalUploadClick = () => {
        if (!vaultUploadsAllowed) {
            router.push(vaultUpgradeHref);
            return;
        }
        setUploadContext("legal");
        setUploadTargetContract(null);
        uploadInputRef.current?.click();
    };

    const handleOtherUploadClick = () => {
        if (!vaultUploadsAllowed) {
            router.push(vaultUpgradeHref);
            return;
        }
        setUploadContext("other");
        setUploadTargetContract(null);
        uploadInputRef.current?.click();
    };

    const handleSignedDocumentSelected = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        const targetContract = uploadTargetContract;
        event.target.value = "";

        if (!file) return;

        if (targetContract && file.type !== "application/pdf") {
            toast("Signed contracts must be uploaded as PDF files.", "error");
            return;
        } else if (!targetContract && !matchesAllowedUpload(file)) {
            toast("Upload a PDF, JPG, PNG, or DOCX file.", "error");
            return;
        }

        if (file.size > VAULT_MAX_FILE_BYTES) {
            toast("Files must be 10 MB or smaller.", "error");
            return;
        }

        try {
            const id = crypto.randomUUID();
            const createdAt = new Date().toISOString();

            if (targetContract) {
                if (!contractSignedCopyUploadAllowed) {
                    router.push("/upgrade?plan=standard");
                    return;
                }

                const nextDocument: DocumentMeta = {
                    id,
                    householdId: employee.householdId ?? settings?.activeHouseholdId ?? "default",
                    type: "archive",
                    employeeId: employee.id,
                    periodId: targetContract.id,
                    fileName: file.name,
                    mimeType: file.type || "application/octet-stream",
                    source: "uploaded",
                    vaultCategory: "contracts",
                    sizeBytes: file.size,
                    createdAt,
                };

                await saveDocumentFile(id, file);
                await saveDocumentMeta(nextDocument);
                await updateContractStatus(targetContract.id, "signed_copy_stored", { signedDocumentId: id });
                if (onDocumentsChange) onDocumentsChange();
                toast("Signed copy saved.", "success");
                return;
            }

            const vaultCategory: VaultCategory =
                uploadContext === "legal" ? "compliance" : "employee-docs";

            const nextDocument: DocumentMeta = {
                id,
                householdId: settings?.activeHouseholdId ?? "default",
                type: "archive",
                employeeId: employee.id,
                fileName: file.name,
                mimeType: file.type || "application/octet-stream",
                source: "uploaded",
                vaultCategory,
                sizeBytes: file.size,
                createdAt,
            };

            await saveDocumentFile(id, file);
            await saveDocumentMeta(nextDocument);
            toast("Document uploaded.", "success");
            if (onDocumentsChange) onDocumentsChange();
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not save that file.", "error");
        } finally {
            setUploadTargetContract(null);
            setUploadContext(null);
        }
    };

    const handleDeleteVaultDocument = async (document: DocumentMeta) => {
        if (!vaultUploadsAllowed) return;
        if (typeof window !== "undefined" && !window.confirm(`Delete ${document.fileName}?`)) {
            return;
        }

        try {
            setDeletingDocumentId(document.id);
            await deleteDocumentMeta(document.id);
            if (previewDoc?.id === document.id) {
                if (previewUrl) URL.revokeObjectURL(previewUrl);
                setPreviewDoc(null);
                setPreviewFileName(undefined);
                setPreviewUrl(null);
            }
            toast("Document removed from Vault.", "success");
            if (onDocumentsChange) onDocumentsChange();
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not delete that file.", "error");
        } finally {
            setDeletingDocumentId(null);
        }
    };

    return (
        <div className="space-y-6">
            <input
                ref={uploadInputRef}
                type="file"
                accept=".pdf,.jpg,.jpeg,.png,.docx"
                className="hidden"
                onChange={handleSignedDocumentSelected}
            />
            
            <div className="flex items-center gap-1 border-b border-[var(--border)] -mx-4 overflow-x-auto px-4 no-scrollbar lg:mx-0 lg:px-0">
                {(["Payslips", "Contracts", "Legal", "Other"] as const).map((tab) => (
                    <button
                        key={tab}
                        type="button"
                        onClick={() => setActiveTab(tab)}
                        className={`whitespace-nowrap border-b-2 px-4 py-3 text-sm font-bold transition-colors ${activeTab === tab ? "border-[var(--primary)] text-[var(--primary)]" : "border-transparent text-[var(--text-muted)] hover:text-[var(--text)]"}`}
                    >
                        {tab}
                    </button>
                ))}
            </div>

            {(activeTab === "Payslips" && filteredPayslipDocuments.length > 0) ||
            (activeTab === "Legal" && filteredLegalDocuments.length > 0) ||
            (activeTab === "Other" && filteredOtherDocuments.length > 0) ? (
                <div className="flex items-center justify-between gap-3">
                    <input
                        type="text"
                        value={search}
                        onChange={(event) => setSearch(event.target.value)}
                        placeholder={`Search ${activeTab.toLowerCase()}...`}
                        className="w-full max-w-xs rounded-xl border border-[var(--border)] bg-[var(--surface-1)] px-3 py-2 text-sm text-[var(--text)] placeholder:text-[var(--text-muted)]"
                    />
                </div>
            ) : null}

            {activeTab === "Contracts" && filteredContracts.length > 0 && (
                <div className="inline-flex rounded-full border border-orange-200 bg-orange-50 px-3 py-1.5 text-xs text-orange-800">
                    <strong>Review before signing:</strong>&nbsp;Templates are starting points. Verify with a labour lawyer if unsure.
                </div>
            )}

            {activeTab === "Payslips" && (
                filteredPayslipDocuments.length > 0 ? (
                    <DataTable<DocumentMeta>
                        data={filteredPayslipDocuments}
                        keyField={(doc) => doc.id}
                        emptyMessage="No payslips match your filters."
                        columns={[
                            {
                                key: "fileName",
                                label: "File",
                                render: (doc) => (
                                    <div className="flex items-center gap-3">
                                        <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                            <FileText className="h-4 w-4 text-[var(--primary)]" />
                                        </div>
                                        <span className="type-body-bold text-[var(--text)]">{doc.fileName}</span>
                                    </div>
                                ),
                            },
                            {
                                key: "storage",
                                label: "Storage",
                                render: (doc) => (
                                    <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                        <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />
                                        <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">
                                            This device
                                        </span>
                                    </div>
                                ),
                            },
                            {
                                key: "date",
                                label: "Added",
                                render: (doc) => (
                                    <span className="type-body text-[var(--text-muted)]">
                                        {format(new Date(doc.createdAt), "d MMM yyyy")}
                                    </span>
                                ),
                            },
                            {
                                key: "actions",
                                label: "",
                                align: "right",
                                render: (doc) => (
                                    <Button
                                        variant="ghost"
                                        size="sm"
                                        className="h-9 w-9 p-0"
                                        onClick={() => void handlePreview(doc)}
                                    >
                                        <Eye className="h-4 w-4 text-[var(--primary)]" />
                                    </Button>
                                ),
                            },
                        ]}
                    />
                ) : (
                    <EmptyState
                        title="No payslips yet"
                        description="Payslip PDFs will appear here automatically after you finalise a pay period for this employee."
                        icon={FileText}
                        actionLabel="Create payslip"
                        actionHref={`/wizard?empId=${employee.id}`}
                    />
                )
            )}

            {activeTab === "Contracts" ? (
                contracts.length > 0 ? (
                    <div className="space-y-6">
                        <div className="flex items-center justify-end">
                            <Link href={`/contracts/new?employeeId=${employee.id}`}>
                                <Button className="gap-2 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold">
                                    <ScrollText className="h-4 w-4" /> New Contract
                                </Button>
                            </Link>
                        </div>

                        <div className="space-y-4">
                            {filteredContracts.map((contract) => (
                                <ContractRow
                                    key={contract.id}
                                    contract={contract}
                                    employee={employee}
                                    onViewPreview={() => openContractPreview(contract)}
                                    onDownloadPdf={() => downloadContract(contract)}
                                    onUploadSigned={() => handleContractUploadClick(contract)}
                                    onViewSigned={() => {
                                        if (contract.signedDocumentId) {
                                            const doc = documents.find((d) => d.id === contract.signedDocumentId);
                                            if (doc) handlePreview(doc);
                                            else toast("Signed document could not be found.", "error");
                                        }
                                    }}
                                    onMarkFinal={() => handleMarkFinal(contract)}
                                    onDelete={() => handleDeleteContract(contract)}
                                />
                            ))}
                        </div>
                    </div>
                ) : (
                    <>
                        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-end mb-6">
                            <Link href={`/contracts/new?employeeId=${employee.id}`}>
                                <Button className="gap-2 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold">
                                    <ScrollText className="h-4 w-4" /> New Contract
                                </Button>
                            </Link>
                        </div>
                        <EmptyState
                            title="No contracts yet"
                            description={`Create an employment contract for ${employee.name}.`}
                            icon={ScrollText}
                            actionLabel="Create contract"
                            actionHref={`/contracts/new?employeeId=${employee.id}`}
                        />
                    </>
                )
            ) : activeTab === "Legal" ? (
                legalDocuments.length === 0 ? (
                    vaultUploadsAllowed ? (
                        <div className="rounded-[22px] border border-dashed border-[var(--border)] bg-[var(--surface-1)] p-10 text-center shadow-sm">
                            <FolderOpen className="mx-auto mb-3 h-10 w-10 text-[var(--text-muted)]" strokeWidth={1.5} />
                            <p className="text-sm font-bold text-[var(--text)]">No legal files for {employee.name}</p>
                            <p className="mt-1 text-sm text-[var(--text-muted)]">Upload legal and compliance paperwork you want to keep with this record.</p>
                            <Button className="mt-4 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]" onClick={handleLegalUploadClick}>
                                Upload document
                            </Button>
                        </div>
                    ) : (
                        <FeatureGateCard
                            title="Store legal & supporting documents"
                            description="Legal uploads are available on Pro."
                            ctaLabel="Upgrade to Pro"
                            href={vaultUpgradeHref}
                            eyebrow="Pro"
                            benefits={[
                                "Private document storage",
                                "Keep legal paperwork attached to each employee",
                                "Upload compliance/supporting records",
                            ]}
                        />
                    )
                ) : (
                    <div className="space-y-4">
                        {vaultUploadsAllowed && (
                            <div className="flex justify-end mb-2">
                                <Button className="gap-2 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold" onClick={handleLegalUploadClick}>
                                    <Upload className="h-4 w-4" /> Upload Document
                                </Button>
                            </div>
                        )}
                        <DataTable<DocumentMeta>
                            data={filteredLegalDocuments}
                            keyField={(doc) => doc.id}
                            emptyMessage="No legal files match your filters."
                            columns={[
                                {
                                    key: "fileName",
                                    label: "File",
                                    render: (doc) => (
                                        <div className="flex items-center gap-3">
                                            <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                <FileText className="h-4 w-4 text-[var(--primary)]" />
                                            </div>
                                            <div>
                                                <p className="type-body-bold text-[var(--text)]">{doc.fileName}</p>
                                                <p className="text-xs text-[var(--text-muted)]">
                                                    {VAULT_CATEGORIES.find((category) => category.value === doc.vaultCategory)?.label ?? "Legal"}
                                                </p>
                                            </div>
                                        </div>
                                    ),
                                },
                                {
                                    key: "storage",
                                    label: "Storage",
                                    render: (doc) => (
                                        <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                            <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />
                                            <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">This device</span>
                                        </div>
                                    ),
                                },
                                {
                                    key: "date",
                                    label: "Added",
