"use client";

import * as React from "react";
import { KeyRound, Loader2, AlertCircle } from "lucide-react";
import { deriveKey, encryptData } from "@/lib/crypto";

interface RecoveryKeyInputProps {
    onComplete: (key: string, cryptoKey: CryptoKey) => void;
    expectedValidationToken?: string; // TBD: used if we want to validate the key immediately
}

export function RecoveryKeyInput({ onComplete }: RecoveryKeyInputProps) {
    const [inputValue, setInputValue] = React.useState("");
    const [error, setError] = React.useState<string | null>(null);
    const [isLoading, setIsLoading] = React.useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        const cleanKey = inputValue.trim().replace(/\s+/g, '');
        if (!cleanKey || cleanKey.length < 32) {
            setError("Please enter a valid recovery key.");
            return;
        }

        setIsLoading(true);

        try {
            // Derive the actual Web Crypto key to ensure the format is technically somewhat valid
            const cryptoKey = await deriveKey(cleanKey);

            // Here we could technically decrypt a test payload from the server to validate it's the *correct* key.
            // For now, assume it's valid if derivation doesn't throw.
            onComplete(cleanKey, cryptoKey);
        } catch (err) {
            console.error("Key derivation error:", err);
            setError("Invalid key format. Please check your recovery key and try again.");
            setIsLoading(false);
        }
    };

    return (
        <div className="w-full bg-[var(--surface-raised)] border border-[var(--border)] rounded-3xl p-6 sm:p-8 shadow-[var(--shadow-lg)] animate-fade-in">
            <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-[var(--primary)]/10 text-[var(--primary)] mb-6 shadow-sm border border-[var(--primary)]/20">
                    <KeyRound className="w-7 h-7" strokeWidth={2.5} />
                </div>
                <h1 className="font-serif text-2xl font-bold text-[var(--text)] mb-3 tracking-tight">
                    Enter Recovery Key
                </h1>
                <p className="text-[var(--text-muted)] text-[0.95rem] leading-relaxed max-w-[320px] mx-auto">
                    To decrypt your synced data on this device, please enter your 256-bit recovery key.
                </p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
                {error && (
                    <div className="p-4 bg-[var(--danger-soft)] text-[var(--danger)] border border-[var(--danger-border)] rounded-2xl text-sm flex items-start space-x-3 animate-slide-down">
                        <AlertCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
                        <span className="font-medium">{error}</span>
                    </div>
                )}

                <div className="space-y-3">
                    <label className="text-sm font-semibold text-[var(--text)]" htmlFor="recovery-key">
                        Recovery Key
                    </label>
                    <textarea
                        id="recovery-key"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        className="w-full p-4 bg-[var(--bg)] border border-[var(--border)] rounded-2xl text-[var(--text)] font-mono resize-none focus:outline-none focus:ring-2 focus:ring-[var(--primary)] focus:border-transparent transition-all"
                        placeholder="AAAA-BBBB-CCCC-DDDD..."
                        rows={3}
                        required
                        disabled={isLoading}
                    />
                </div>

                <button
                    type="submit"
                    disabled={isLoading || !inputValue.trim()}
                    className="w-full flex justify-center items-center py-3.5 px-4 bg-[var(--primary)] text-white font-bold rounded-xl active-scale transition-all hover:bg-[var(--primary-hover)] shadow-[0_2px_10px_rgba(0,122,77,0.15)] disabled:opacity-70 disabled:cursor-not-allowed"
                >
                    {isLoading ? (
                        <>
                            <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                            Unlocking...
                        </>
                    ) : (
                        "Unlock Data"
                    )}
                </button>
            </form>
        </div>
    );
}

"use client";

import * as React from "react";
import { Loader2, CheckCircle2, AlertCircle, CloudUpload } from "lucide-react";
import { syncEngine, SyncProgressData } from "@/lib/sync-engine";

interface SyncProgressProps {
    onComplete?: () => void;
}

export function SyncProgress({ onComplete }: SyncProgressProps) {
    const [progressData, setProgressData] = React.useState<SyncProgressData>({
        status: 'idle',
        currentTask: 'Waiting to start...',
        progress: 0
    });

    React.useEffect(() => {
        syncEngine.onProgressUpdate((data) => {
            setProgressData(data);
            if (data.status === 'completed' && onComplete) {
                // Give it a second so the user sees 100%
                setTimeout(onComplete, 1000);
            }
        });
    }, [onComplete]);

    const handleStart = async () => {
        try {
            await syncEngine.runMigration();
        } catch (error) {
           // Error is handled in the callback
        }
    };

    if (progressData.status === 'idle') {
        return (
            <div className="w-full bg-[var(--surface-raised)] border border-[var(--border)] rounded-3xl p-6 sm:p-8 shadow-[var(--shadow-lg)] text-center animate-fade-in">
                <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-blue-50 text-blue-600 mb-6 shadow-sm border border-blue-100">
                    <CloudUpload className="w-7 h-7" strokeWidth={2.5} />
                </div>
                <h2 className="font-serif text-2xl font-bold text-[var(--text)] mb-3 tracking-tight">Sync Your Data</h2>
                <p className="text-[var(--text-muted)] text-[0.95rem] leading-relaxed max-w-[320px] mx-auto mb-8">
                    We will now encrypt all your local offline data and upload it securely to your premium cloud account.
                </p>
                <button
                    onClick={handleStart}
                    className="w-full flex justify-center items-center py-3.5 px-4 bg-[var(--primary)] text-white font-bold rounded-xl active-scale transition-all hover:bg-[#006640] shadow-[0_2px_10px_rgba(0,122,77,0.15)]"
                >
                    Start Sync
                </button>
            </div>
        );
    }

    const { status, progress, currentTask, error } = progressData;

    return (
        <div className="w-full bg-[var(--surface-raised)] border border-[var(--border)] rounded-3xl p-6 sm:p-8 shadow-[var(--shadow-lg)] animate-fade-in">
            <div className="flex flex-col items-center text-center">

                {status === 'running' && (
                    <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-blue-50 text-blue-600 mb-6 shadow-sm border border-blue-100 animate-pulse">
                        <Loader2 className="w-7 h-7 animate-spin" strokeWidth={2.5} />
                    </div>
                )}

                {status === 'completed' && (
                    <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-green-50 text-green-600 mb-6 shadow-sm border border-green-100">
                        <CheckCircle2 className="w-7 h-7" strokeWidth={2.5} />
                    </div>
                )}

                {status === 'error' && (
                    <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-red-50 text-red-600 mb-6 shadow-sm border border-red-100">
                        <AlertCircle className="w-7 h-7" strokeWidth={2.5} />
                    </div>
                )}

                <h2 className="font-serif text-xl sm:text-2xl font-bold text-[var(--text)] mb-2 tracking-tight">
                    {status === 'running' ? 'Migrating Data...' :
                     status === 'completed' ? 'Migration Complete!' : 
                     'Sync Failed'}
                </h2>

                <p className={`text-[0.95rem] mb-8 font-medium ${status === 'error' ? 'text-red-600 max-w-[320px]' : 'text-[var(--text-muted)]'}`}>
                    {status === 'error' ? error : currentTask}
                </p>

                <div className="w-full max-w-sm mx-auto">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-wider">Progress</span>
                        <span className="text-sm font-bold text-[var(--text)]">{Math.round(progress)}%</span>
                    </div>
                    <div className="w-full h-3 bg-[var(--border)] rounded-full overflow-hidden">
                        <div 
                            className={`h-full transition-all duration-500 ease-out origin-left ${
                                status === 'error' ? 'bg-red-500' : 
                                status === 'completed' ? 'bg-green-500' : 
                                'bg-[var(--primary)]'
                            }`}
                            style={{ 
                                width: `${progress}%`,
                            }}
                        />
                    </div>
                </div>

                {status === 'error' && (
                    <button
                        onClick={handleStart}
                        className="mt-8 px-6 py-2.5 bg-red-50 text-red-700 font-bold rounded-xl active-scale transition-all hover:bg-red-100 shadow-sm border border-red-200"
                    >
                        Try Again
                    </button>
                )}
            </div>
        </div>
    );
}

"use client";

import * as React from "react";
import { createClient } from "./supabase/client";
import { syncEngine } from "./sync-engine";

import { syncService } from "./sync-service";

/**
 * Detailed representation of the app's current operating mode.
 * - 'local_guest': No account, data lives only securely in local device storage.
 * - 'account_unlocked': User is logged into Supabase AND has a valid memory crypto key. Fully capable of syncing.
 * - 'account_locked': User is logged in, but we still need them to provide their recovery key.
 */
export type AppMode = "local_guest" | "account_unlocked" | "account_locked";

interface AppModeContextValue {
    mode: AppMode;
    setMode: React.Dispatch<React.SetStateAction<AppMode>>;
    unlockAccount: (key: CryptoKey, userId: string) => void;
    lockAccount: () => void;
}

const AppModeContext = React.createContext<AppModeContextValue | null>(null);

export function AppModeProvider({ children }: { children: React.ReactNode }) {
    const [mode, setMode] = React.useState<AppMode>("local_guest");
    const supabase = createClient();

    React.useEffect(() => {
        let mounted = true;

        async function initMode() {
            const { data: { session } } = await supabase.auth.getSession();
            if (!mounted) return;

            if (session) {
                // They are logged in, but the key is only in memory, so it's always locked on load
                setMode("account_locked");
            } else {
                setMode("local_guest");
            }
        }

        initMode();

        const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
            if (event === "SIGNED_OUT") {
                setMode("local_guest");
                syncEngine.setCryptoKey(null);
            } else if (event === "SIGNED_IN" && mode === "local_guest") {
                setMode("account_locked");
            }
        });

        return () => {
            mounted = false;
            authListener.subscription.unsubscribe();
        };
    }, [supabase.auth, mode]);

    const unlockAccount = React.useCallback((key: CryptoKey, userId: string) => {
        syncEngine.setCryptoKey(key);
        syncService.init(userId, key);
        setMode("account_unlocked");
    }, []);

    const lockAccount = React.useCallback(() => {
        syncEngine.setCryptoKey(null);
        setMode("account_locked");
    }, []);

    return (
        <AppModeContext.Provider value={{ mode, setMode, unlockAccount, lockAccount }}>
            {children}
        </AppModeContext.Provider>
    );
}

export function useAppMode() {
    const context = React.useContext(AppModeContext);
    if (!context) {
        throw new Error("useAppMode must be used within an AppModeProvider");
    }
    return context;
}

