function getRequiredEnv(name: string): string {
    const value = process.env[name]?.trim();
    if (!value || value === "undefined" || value === "null") {
        throw new BillingConfigError(`${name} is missing.`);
    }
    return value;
}

function getPaystackSecretKey(): string {
